(function () {
  "use strict";

  function submitForm(form) {
    var method = form.getAttribute("hx-post") ? "POST" : (form.method || "GET").toUpperCase();
    var url = form.getAttribute("hx-post") || form.action;
    var targetSelector = form.getAttribute("hx-target");
    var target = targetSelector ? document.querySelector(targetSelector) : null;
    var body = new FormData(form);

    fetch(url, {
      method: method,
      body: body,
      credentials: "same-origin",
      headers: { "HX-Request": "true" }
    }).then(function (response) {
      return response.text().then(function (text) {
        if (target) {
          target.innerHTML = text;
        }
      });
    }).catch(function () {
      if (target) {
        target.textContent = "Request failed.";
      }
    });
  }

  document.addEventListener("submit", function (event) {
    var form = event.target;
    if (!form || !form.getAttribute || !form.getAttribute("hx-post")) {
      return;
    }
    event.preventDefault();
    submitForm(form);
  });
})();
